// DeleteExpired purges every entry whose deadline has passed and returns the
// number of entries removed. Lazy expiry on Get only reclaims keys that are
// read again, so a periodic call to DeleteExpired bounds memory for keys that
// are written once and never read.
func (c *Cache) DeleteExpired() int {
	c.mu.Lock()
	defer c.mu.Unlock()

	removed := 0
	for key, it := range c.items {
		if c.expired(it) {
			delete(c.items, key)
			removed++
		}
	}
	return removed
}

// expired reports whether it has passed its expiry deadline. Entries with a
// zero deadline never expire. The caller must hold c.mu.
func (c *Cache) expired(it item) bool {
	return !it.expireAt.IsZero() && !c.now().Before(it.expireAt)
}
