package csvagg

// GroupStat holds the running aggregate for a single group.
type GroupStat struct {
	Sum   int
	Count int
}

// Mean returns the average value for the group. It returns 0 when the group
// has no rows, avoiding a divide-by-zero.
func (g GroupStat) Mean() float64 {
	if g.Count == 0 {
		return 0
	}
	return float64(g.Sum) / float64(g.Count)
}

// GroupStats groups rows by keyCol and, for each group, accumulates both the
// sum and the count of the integers in valCol. It shares the same validation
// rules and error semantics as GroupSum.
func (t *Table) GroupStats(keyCol, valCol string) (map[string]GroupStat, error) {
	keyIdx, err := t.columnIndex(keyCol)
	if err != nil {
		return nil, err
	}
	valIdx, err := t.columnIndex(valCol)
	if err != nil {
		return nil, err
	}

	stats := make(map[string]GroupStat)
	for rowNum, row := range t.Rows {
		if keyIdx >= len(row) || valIdx >= len(row) {
			return nil, errShortRow(rowNum, len(row), keyIdx, valIdx)
		}
		v, err := parseValue(row, valIdx, valCol, rowNum)
		if err != nil {
			return nil, err
		}
		key := row[keyIdx]
		s := stats[key]
		s.Sum += v
		s.Count++
		stats[key] = s
	}
	return stats, nil
}

// GroupMean groups rows by keyCol and returns the average of valCol per group.
func (t *Table) GroupMean(keyCol, valCol string) (map[string]float64, error) {
	stats, err := t.GroupStats(keyCol, valCol)
	if err != nil {
		return nil, err
	}
	means := make(map[string]float64, len(stats))
	for k, s := range stats {
		means[k] = s.Mean()
	}
	return means, nil
}
