	subs   map[string][]chan Event
	buffer int
	closed bool
}

// New returns an empty Bus whose subscriber channels are buffered with
// DefaultBuffer slots.
func New() *Bus {
	return NewBuffered(DefaultBuffer)
}

// NewBuffered returns an empty Bus whose subscriber channels are buffered
// with the given number of slots. A negative size is treated as zero
// (an unbuffered channel).
func NewBuffered(buffer int) *Bus {
	if buffer < 0 {
		buffer = 0
	}
	return &Bus{
		subs:   make(map[string][]chan Event),
		buffer: buffer,
	}
}

// Subscribe registers a new subscriber for the given topic and returns a
// receive-only channel on which the subscriber will receive published
// events. Each call returns an independent channel, so the same topic may
// have many subscribers.
//
// If the Bus is already closed, Subscribe returns an already-closed
// channel so that a range over it terminates immediately.
func (b *Bus) Subscribe(topic string) <-chan Event {
	ch := make(chan Event, b.buffer)

	b.mu.Lock()
	defer b.mu.Unlock()

	if b.closed {
		close(ch)
		return ch
	}
	b.subs[topic] = append(b.subs[topic], ch)
	return ch
}

// Unsubscribe removes a single subscriber channel previously returned by
// Subscribe and closes it. It reports whether a matching subscription was
// found and removed. Unsubscribing a channel that is not subscribed (or
// unsubscribing on a closed Bus, where every channel is already closed) is
// a no-op that returns false.
func (b *Bus) Unsubscribe(topic string, ch <-chan Event) bool {
	b.mu.Lock()
	defer b.mu.Unlock()

	if b.closed {
		return false
	}
	chans := b.subs[topic]
	for i, sub := range chans {
		if (<-chan Event)(sub) != ch {
			continue
		}
		// Remove index i while preserving the order of the remaining
		// subscribers.
		b.subs[topic] = append(chans[:i:i], chans[i+1:]...)
		if len(b.subs[topic]) == 0 {
			delete(b.subs, topic)
		}
		close(sub)
		return true
	}
	return false
}

