package lrucache

import (
	"reflect"
	"testing"
)

func TestWithOnEvictFiresOnEviction(t *testing.T) {
	type evicted struct {
		key   string
		value int
	}
	var got []evicted

	c, err := New[string, int](2, WithOnEvict[string, int](func(k string, v int) {
		got = append(got, evicted{k, v})
	}))
	if err != nil {
		t.Fatalf("New: %v", err)
	}

	c.Put("a", 1)
	c.Put("b", 2)
	// No eviction yet.
	if len(got) != 0 {
		t.Fatalf("unexpected evictions before overflow: %v", got)
	}

	c.Put("c", 3) // evicts LRU "a"
	c.Put("d", 4) // evicts LRU "b"

	want := []evicted{{"a", 1}, {"b", 2}}
	if !reflect.DeepEqual(got, want) {
		t.Errorf("evictions = %v, want %v", got, want)
	}
}

func TestOnEvictNotCalledForRemoveOrUpdate(t *testing.T) {
	var calls int
	c, err := New[string, int](2, WithOnEvict[string, int](func(string, int) {
		calls++
	}))
	if err != nil {
		t.Fatalf("New: %v", err)
	}

	c.Put("a", 1)
	c.Put("b", 2)
	c.Put("a", 11) // in-place update, not an eviction
	c.Remove("b")  // explicit remove, not an eviction
	c.Clear()      // clear, not an eviction

	if calls != 0 {
		t.Errorf("onEvict called %d times, want 0 for update/remove/clear", calls)
	}
}

func TestNilOnEvictOptionIgnored(t *testing.T) {
	// A nil callback must be safely ignored, not cause a panic on eviction.
	c, err := New[int, int](1, WithOnEvict[int, int](nil))
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	c.Put(1, 1)
	c.Put(2, 2) // triggers eviction path with nil callback
	if c.Contains(1) {
		t.Errorf("key 1 should have been evicted")
	}
}
